const staticData = $getWorkflowStaticData('global');
if (!staticData.jobLastMsgId) staticData.jobLastMsgId = '0';

const messages = $input.all().map(i => i.json);
const newMsgs = messages.filter(m => m.id && BigInt(m.id) > BigInt(staticData.jobLastMsgId));

if (newMsgs.length === 0) return [];

const newestId = newMsgs.reduce(
  (max, m) => BigInt(m.id) > BigInt(max) ? m.id : max,
  staticData.jobLastMsgId
);
staticData.jobLastMsgId = newestId;

return newMsgs
  .reverse()
  .filter(m => m.content && m.content.trim().startsWith('!jobs'))
  .map(m => ({ json: m }));

const content  = $json.content  || '';
const authorId = $json.author?.id || 'unknown';

// ─── Defaults: edit these to change your preferences ────────────────────────
const DEFAULT_TITLES     = ['Data Scientist', 'ML Engineer', 'AI Engineer', 'Data Analyst'];
const DEFAULT_LIMIT      = 25;
const DEFAULT_SITES      = 'linkedin';
const RESUME_PATH        = '/home/ubuntu/resume.pdf';
const SCRAPER_PATH       = '/home/ubuntu/job-scraper/scraper.py';
const OLLAMA_MODEL       = 'llama3.2:latest';
const OLLAMA_URL         = 'http://localhost:11434/api/chat';
const SKILLS_MATCH_MIN   = 40;
const INTENT_MIN         = 6;
// ────────────────────────────────────────────────────────────────────────────

const params = {
  authorId,
  titles:          [...DEFAULT_TITLES],
  remote:          true,
  hybrid:          true,
  onsite:          false,
  city:            '',
  limit:           DEFAULT_LIMIT,
  sites:           DEFAULT_SITES,
  resumePath:      RESUME_PATH,
  scraperPath:     SCRAPER_PATH,
  ollamaModel:     OLLAMA_MODEL,
  ollamaUrl:       OLLAMA_URL,
  skillsMatchMin:  SKILLS_MATCH_MIN,
  intentToHireMin: INTENT_MIN,
  adzunaAppId:     '',
  adzunaApiKey:    '',
};

const args = content.slice('!jobs'.length).trim();
let remainder = args;

// Extract quoted title: !jobs "Senior Data Scientist" --remote
const quotedMatch = args.match(/^"([^"]+)"/);
if (quotedMatch) {
  params.titles = [quotedMatch[1]];
  remainder = args.slice(quotedMatch[0].length).trim();
} else {
  const firstFlagIdx = remainder.indexOf('--');
  if (firstFlagIdx > 0) {
    const possibleTitle = remainder.slice(0, firstFlagIdx).trim();
    if (possibleTitle) { params.titles = [possibleTitle]; remainder = remainder.slice(firstFlagIdx); }
  } else if (remainder.length > 0 && !remainder.startsWith('--')) {
    params.titles = [remainder];
    remainder = '';
  }
}

// Parse --flag and --flag=value pairs
const flagMatches = remainder.match(/--[\w-]+(?:=[^\s]+)?/g) || [];
for (const flag of flagMatches) {
  const eqIdx = flag.indexOf('=');
  const key   = eqIdx >= 0 ? flag.slice(2, eqIdx) : flag.slice(2);
  const val   = eqIdx >= 0 ? flag.slice(eqIdx + 1) : '';
  switch (key) {
    case 'remote':    params.remote = true;  break;
    case 'hybrid':    params.hybrid = true;  break;
    case 'onsite':    params.onsite = true;  break;
    case 'no-remote': params.remote = false; break;
    case 'no-hybrid': params.hybrid = false; break;
    case 'city':      params.city   = val;   break;
    case 'limit':     params.limit  = Math.min(50, parseInt(val) || DEFAULT_LIMIT); break;
    case 'sites':     params.sites  = val;   break;
  }
}

const titleArg = params.titles.join(' OR ');
let cliArgs = `--title "${titleArg}" --sites "${params.sites}" --limit ${params.limit}`;
if (params.remote) cliArgs += ' --remote';
if (params.hybrid) cliArgs += ' --hybrid';
if (params.onsite) cliArgs += ' --onsite';
if (params.city)   cliArgs += ` --city "${params.city}"`;
if (params.adzunaAppId)  cliArgs += ` --adzuna-app-id "${params.adzunaAppId}"`;
if (params.adzunaApiKey) cliArgs += ` --adzuna-api-key "${params.adzunaApiKey}"`;
params.scraperCliArgs = cliArgs;

return [{ json: params }];

const staticData = $getWorkflowStaticData('global');
const params     = $('Parse Command').first().json;
const stdout     = $json.text || '';

if (!stdout || stdout.trim().length < 50) {
  if (staticData.cachedResumeText) {
    return [{ json: { ...params, resumeText: staticData.cachedResumeText, resumeFromCache: true } }];
  }
  return [{ json: { ...params, resumeText: '(resume unavailable — check /home/ubuntu/resume.pdf)', resumeError: true } }];
}

const resumeText = stdout.trim().slice(0, 4000);
staticData.cachedResumeText = resumeText;

return [{ json: { ...params, resumeText } }];

const params   = $('Cache Resume Text').first().json;
const response = $json;   // { jobs, count, error } from job-scraper service

if (response.error) {
  return [{ json: { ...params, scraperError: true, scraperErrorMsg: String(response.error).slice(0, 500), jobs: [] } }];
}

const jobs = response.jobs || [];
if (!Array.isArray(jobs)) {
  return [{ json: { ...params, scraperError: true, scraperErrorMsg: 'Service returned non-array jobs', jobs: [] } }];
}

return [{ json: { ...params, scraperError: false, jobs, totalFound: jobs.length } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenJobIds) staticData.seenJobIds = [];

const jobs   = $json.jobs || [];
const params = { ...$json };
delete params.jobs;

const newJobs = jobs.filter(job => !staticData.seenJobIds.includes(job.id));

if (newJobs.length === 0) {
  return [{ json: { ...params, noNewJobs: true, newJobs: [], newCount: 0 } }];
}

return [{ json: { ...params, noNewJobs: false, newJobs, newCount: newJobs.length } }];

const data = $('Deduplicate Jobs').first().json;
const { newJobs = [], resumeText, ollamaModel, ollamaUrl, skillsMatchMin, intentToHireMin } = data;

if (newJobs.length === 0) return [];

return newJobs.map(job => ({
  json: { resumeText, ollamaModel, ollamaUrl, skillsMatchMin, intentToHireMin, job }
}));

const { resumeText, job } = $json;

const prompt = `You are a job application evaluator. Analyze this job posting against the candidate's resume and return ONLY valid JSON — no explanation, no markdown.

RESUME:
${resumeText}

JOB POSTING:
Title: ${job.title}
Company: ${job.company}
Location: ${job.location} (${job.remote_type})
Salary: ${job.salary || 'Not specified'}
Description: ${job.description}

Return this exact JSON structure:
{
  "intent_to_hire_score": <integer 1-10, 10 = clearly targeting this exact profile>,
  "skills_match_percent": <integer 0-100, only required/strongly-preferred skills>,
  "salary_fit": <"good" | "below_expectations" | "above_expectations" | "unknown">,
  "red_flags": [<up to 3 strings, empty array if none>],
  "strengths": [<2-3 specific resume-to-job matches>],
  "summary": "<2-3 sentence honest assessment of fit>"
}

Scoring guidance:
- intent_to_hire_score: Deduct for vague JD, missing company name, unrealistic requirements. Add for specific team info, clear requirements, salary listed.
- red_flags: Vague role, required degree not on resume, key tools not on resume, suspiciously generic JD, possible ghost job.`;

return [{ json: { ...$json, ollamaPrompt: prompt } }];

const rawContent = $json.message?.content || $json.choices?.[0]?.message?.content || '';

let ev;
try {
  ev = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
} catch (e) {
  ev = {
    intent_to_hire_score: 5,
    skills_match_percent: 50,
    salary_fit:   'unknown',
    red_flags:    [],
    strengths:    ['(AI parse failed — heuristic fallback)'],
    summary:      'Ollama response could not be parsed. Flagged for manual review.',
    _fallback:    true,
  };
}

const validFits = ['good', 'below_expectations', 'above_expectations', 'unknown'];
const evaluation = {
  intent_to_hire_score: Math.min(10, Math.max(1, parseInt(ev.intent_to_hire_score) || 5)),
  skills_match_percent: Math.min(100, Math.max(0, parseInt(ev.skills_match_percent) || 50)),
  salary_fit:           validFits.includes(ev.salary_fit) ? ev.salary_fit : 'unknown',
  red_flags:            Array.isArray(ev.red_flags) ? ev.red_flags.slice(0, 3) : [],
  strengths:            Array.isArray(ev.strengths) ? ev.strengths.slice(0, 3) : [],
  summary:              String(ev.summary || '').slice(0, 600),
  _fallback:            ev._fallback || false,
};

const { ollamaPrompt, ...rest } = $json;
return [{ json: { ...rest, evaluation } }];

const { job, evaluation: ev } = $json;
const skills = ev.skills_match_percent;

const color = skills >= 70 ? 0x57F287 : skills >= 40 ? 0xFEE75C : 0xE67E22;

const salaryEmoji = { good: '✅', below_expectations: '⬇️', above_expectations: '⬆️', unknown: '❓' }[ev.salary_fit] || '❓';
const remoteEmoji = { remote: '🏠', hybrid: '🔀', onsite: '🏢', unknown: '📍' }[job.remote_type] || '📍';
const sourceLabel = { linkedin: 'LinkedIn', indeed: 'Indeed', adzuna: 'Adzuna' }[job.source] || job.source;

const embed = {
  title: `${job.title} @ ${job.company}`.slice(0, 256),
  url:   job.url,
  color,
  fields: [
    { name: '📍 Location',    value: `${job.location || 'Not specified'} ${remoteEmoji} \`${job.remote_type}\``,               inline: true  },
    { name: '💰 Salary',      value: `${salaryEmoji} ${job.salary || 'Not listed'} *(${ev.salary_fit})*`,                      inline: true  },
    { name: '🎯 Skills Match',value: `**${skills}%**`,                                                                          inline: true  },
    { name: '🤝 Hiring Intent',value: `**${ev.intent_to_hire_score}/10**`,                                                     inline: true  },
    { name: '✨ Strengths',   value: ev.strengths.length > 0 ? ev.strengths.map(s => `• ${s}`).join('\n') : '*None identified*', inline: false },
    { name: '⚠️ Red Flags',   value: ev.red_flags.length  > 0 ? ev.red_flags.map(f => `• ${f}`).join('\n')  : '*None detected*',  inline: false },
    { name: '🤖 AI Assessment',value: ev.summary || '*No summary available*',                                                  inline: false },
  ],
  footer: {
    text: `${sourceLabel}${job.posted_date ? ' · Posted: ' + job.posted_date : ''}${ev._fallback ? ' · ⚠️ Heuristic' : ''}`,
  },
  timestamp: new Date().toISOString(),
};

return [{ json: { ...$json, discordEmbed: embed } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenJobIds) staticData.seenJobIds = [];

const allItems = $input.all();
const sent     = allItems.filter(i => i.json._wasSent === true).length;
const filtered = allItems.length - sent;

// Mark ALL analyzed jobs as seen to prevent re-processing on next run
for (const item of allItems) {
  const jobId = item.json.job?.id;
  if (jobId && !staticData.seenJobIds.includes(jobId)) {
    staticData.seenJobIds.push(jobId);
  }
}
// Cap at 5000 to prevent unbounded growth (~100KB max)
if (staticData.seenJobIds.length > 5000) {
  staticData.seenJobIds = staticData.seenJobIds.slice(-5000);
}

return [{ json: { summarySent: sent, summaryFiltered: filtered, summaryTotal: allItems.length } }];

